(function(){'use strict';const THEME_KEY='events_admin_theme';const THEME_LIGHT='light';const THEME_DARK='dark';function getCurrentTheme(){const stored=localStorage.getItem(THEME_KEY);if(stored){return stored;}if(window.matchMedia&&window.matchMedia('(prefers-color-scheme:dark)').matches){return THEME_DARK;}return THEME_LIGHT;}function setTheme(theme){const html=document.documentElement;if(theme===THEME_DARK){html.setAttribute('data-theme',THEME_DARK);localStorage.setItem(THEME_KEY,THEME_DARK);}else{html.removeAttribute('data-theme');localStorage.setItem(THEME_KEY,THEME_LIGHT);}updateThemeToggle(theme);window.dispatchEvent(new CustomEvent('themechange',{detail:{theme}}));}function toggleTheme(){const current=getCurrentTheme();const next=current===THEME_DARK?THEME_LIGHT:THEME_DARK;setTheme(next);}function updateThemeToggle(theme){const toggle=document.getElementById('theme-toggle');if(!toggle)return;const icon=toggle.querySelector('i');const label=toggle.getAttribute('aria-label');if(theme===THEME_DARK){toggle.setAttribute('aria-pressed','true');if(icon){icon.className='bi bi-sun-fill';}toggle.title='Light mode';}else{toggle.setAttribute('aria-pressed','false');if(icon){icon.className='bi bi-moon-fill';}toggle.title='Dark mode';}}function initTheme(){const theme=getCurrentTheme();setTheme(theme);if(window.matchMedia){window.matchMedia('(prefers-color-scheme:dark)').addEventListener('change',(e)=>{if(!localStorage.getItem(THEME_KEY)){setTheme(e.matches?THEME_DARK:THEME_LIGHT);}});}const toggle=document.getElementById('theme-toggle');if(toggle){toggle.addEventListener('click',toggleTheme);}}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initTheme);}else{initTheme();}window.eventsAdminTheme={getCurrentTheme,setTheme,toggleTheme};})();